def metric_display_label(metric_key: str, fallback: str) -> str:
    """Teknik anahtarı değiştirmeden okunabilir metrik adını döndürür."""
    label = METRIC_LABELS.get(metric_key, fallback)
    # Mali Bünye etiketleri kullanıcı tarafından elle düzenlendiği için aynen
    # korunur. Diğer raporlarda para birimi kısaltmaları açık gösterilir.
    if not metric_key.startswith("mali_bunye."):
        label = re.sub(r"(?<!\w)TP(?!\w)", "Türk Parası", label)
        label = re.sub(r"(?<!\w)YP(?!\w)", "Yabancı Para", label)
    return label
